import{_ as t,o as e,c as i,a2 as s}from"./chunks/framework.BnBoz4Zl.js";const l="/anjian-workbuddy-bluebook-site/assets/001_image_M29JbJQ3po.C3AVfMmC.png",r="/anjian-workbuddy-bluebook-site/assets/002_byKl8HZ2_TtombzmOwo.E4YA6n5o.jpg",n="/anjian-workbuddy-bluebook-site/assets/003_image_D0c8blIsEo.Bv8PlDd6.png",d="/anjian-workbuddy-bluebook-site/assets/004_test_SSsAbxS8po.S-iFsVqn.jpg",g=JSON.parse('{"title":"第 16 章 收藏不是知识管理，能再次用起来才是","description":"继续向前一步：如果一个人同时使用 WPS、ima、Obsidian、微信收藏、会议记录和本地文件，怎样分工才能避免“每个地方都有一份，但没有一份可信”。 一个稳健的个人知识系统可以有多个入口，但只能有清楚的主版本：","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 16 章 收藏不是知识管理，能再次用起来才是/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 16 章 收藏不是知识管理，能再次用起来才是/index.md","lastUpdated":1783659790000}'),o={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 16 章 收藏不是知识管理，能再次用起来才是/index.md"};function p(h,a,b,c,k,u){return e(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="第-16-章-收藏不是知识管理-能再次用起来才是" tabindex="-1">第 16 章 收藏不是知识管理，能再次用起来才是 <a class="header-anchor" href="#第-16-章-收藏不是知识管理-能再次用起来才是" aria-label="Permalink to &quot;第 16 章 收藏不是知识管理，能再次用起来才是&quot;">​</a></h1><h2 id="工具都装了-知识还是散的" tabindex="-1">工具都装了，知识还是散的 <a class="header-anchor" href="#工具都装了-知识还是散的" aria-label="Permalink to &quot;工具都装了，知识还是散的&quot;">​</a></h2><p>继续向前一步：如果一个人同时使用 WPS、ima、Obsidian、微信收藏、会议记录和本地文件，怎样分工才能避免“每个地方都有一份，但没有一份可信”。</p><h2 id="先决定主版本-再连接工具" tabindex="-1">先决定主版本，再连接工具 <a class="header-anchor" href="#先决定主版本-再连接工具" aria-label="Permalink to &quot;先决定主版本，再连接工具&quot;">​</a></h2><p>一个稳健的个人知识系统可以有多个入口，但只能有清楚的主版本：</p><table tabindex="0"><thead><tr><th>系统</th><th>推荐角色</th><th>不建议承担</th></tr></thead><tbody><tr><td>WPS / Kdocs</td><td>工作文档、表格、协作笔记和团队知识</td><td>同时充当所有私人原始资料的唯一备份</td></tr><tr><td>ima</td><td>微信生态收集、移动问答和知识库检索</td><td>保存没有来源的二手结论</td></tr><tr><td>Obsidian</td><td>本地 Markdown、双链、专题 Wiki 和长期迁移</td><td>未备份情况下让自动化批量移动或重命名</td></tr><tr><td>微信收藏 / 灵感工具</td><td>低摩擦入口和临时收件箱</td><td>永久归档与结构化检索</td></tr><tr><td>飞书 / 腾讯文档</td><td>团队协作、评论和发布副本</td><td>默认扩大私人资料可见范围</td></tr></tbody></table><h2 id="场景一-灵感来了-只记下一句话" tabindex="-1">场景一：灵感来了，只记下一句话 <a class="header-anchor" href="#场景一-灵感来了-只记下一句话" aria-label="Permalink to &quot;场景一：灵感来了，只记下一句话&quot;">​</a></h2><p>灵感最怕两种处理：一种是没来得及记，另一种是 AI 立刻把一句话扩写成一篇看似完整、却已经偏离原意的文章。</p><ul><li><a href="https://skillhub.cn/skills/inspiration-hunter-skill" target="_blank" rel="noreferrer">灵感捕手</a>：自动分类并写入 Markdown 收件箱；</li><li><a href="https://skillhub.cn/skills/ima-skills" target="_blank" rel="noreferrer">ima-skills</a>或 <a href="https://skillhub.cn/skills/ima-pro" target="_blank" rel="noreferrer">ima</a>：移动端记录、知识库读写与检索；</li><li>Obsidian 本地目录作为长期主版本时，可接入后文的 Wiki Skill。</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把下面内容记入“灵感收件箱”，保留我的原话，不扩写、不评价：“AI 工具真正的门槛不是提示词，而是验收结果。”</span></span></code></pre></div><p><img src="'+l+'" alt="" loading="lazy"></p><h2 id="场景二-微信收藏很多-真正写作时还是搜不到" tabindex="-1">场景二：微信收藏很多，真正写作时还是搜不到 <a class="header-anchor" href="#场景二-微信收藏很多-真正写作时还是搜不到" aria-label="Permalink to &quot;场景二：微信收藏很多，真正写作时还是搜不到&quot;">​</a></h2><ul><li><a href="https://skillhub.cn/skills/wechat-favorite" target="_blank" rel="noreferrer">微信收藏知识库</a>：导出、分类，并可选择进入 ima、Obsidian 或 Notion；</li><li><a href="https://skillhub.cn/skills/url-to-obsidian" target="_blank" rel="noreferrer">URL to Obsidian</a>：抓取网页、总结并保存到 Vault；</li><li><a href="https://skillhub.cn/skills/wxpublic-fetch" target="_blank" rel="noreferrer">公众号内容提取</a>：将公众号文章保存为本地 Markdown。</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>处理本周微信收藏，只读，不删除原收藏。</span></span></code></pre></div><p><img src="'+r+'" alt="" loading="lazy"></p><h2 id="场景三-ima-作为移动知识入口" tabindex="-1">场景三：ima 作为移动知识入口 <a class="header-anchor" href="#场景三-ima-作为移动知识入口" aria-label="Permalink to &quot;场景三：ima 作为移动知识入口&quot;">​</a></h2><p>ima 的优势不是“问答更聪明”，而是手机收集、知识库读写和微信上下文衔接。使用 <a href="https://skillhub.cn/skills/ima-skills" target="_blank" rel="noreferrer">ima-skills</a> 时，先明确目标知识库和写入规则。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>将我刚选择的 3 份文件放入 ima“WorkBuddy 案例库”的收件箱。</span></span></code></pre></div><p><img src="'+n+'" alt="" loading="lazy"></p><h2 id="场景四-obsidian-不是文件夹-而是可维护的-wiki" tabindex="-1">场景四：Obsidian 不是文件夹，而是可维护的 Wiki <a class="header-anchor" href="#场景四-obsidian-不是文件夹-而是可维护的-wiki" aria-label="Permalink to &quot;场景四：Obsidian 不是文件夹，而是可维护的 Wiki&quot;">​</a></h2><ul><li><a href="https://skillhub.cn/skills/obsidian-core-notes" target="_blank" rel="noreferrer">Obsidian 资料整理</a>：维护核心笔记、专题综合和目录链接；</li><li><a href="https://skillhub.cn/skills/obsidian-memory" target="_blank" rel="noreferrer">agent + Obsidian 长期记忆</a>：在明确项目边界后读写长期记忆。</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把一篇公众号文章交给 WorkBuddy 解析，再要求放进指定的 Obsidian 素材目录。</span></span></code></pre></div><p>WorkBuddy 能识别文章正文和作者，并生成 Markdown 条目。</p><p><img src="'+d+'" alt="" loading="lazy"></p>',24)])])}const _=t(o,[["render",p]]);export{g as __pageData,_ as default};
